def _specialist(slug: str, name: str, description: str) -> Agent:
    return Agent(
        name=name,
        instructions=ROLE_INSTRUCTIONS[slug],
        handoff_description=description,
        input_guardrails=[sensitive_action_guardrail],
        output_guardrails=[unsupported_completion_claim_guardrail],
    )


def build_department_agents() -> dict[str, Agent]:
    requirements = _specialist("requirements-and-planning-specialist", "Requirements and Planning Specialist", "Use for requirements, acceptance criteria and plans.")
    architect = _specialist("software-architect", "Software Architect", "Use for boundaries, contracts, decisions, compatibility and migrations.")
    implementation = _specialist("implementation-and-maintenance-engineer", "Implementation and Maintenance Engineer", "Use for approved, scoped implementation through host-injected tools only.")
    testing = _specialist("test-and-quality-engineer", "Test and Quality Engineer", "Use for validation strategy and acceptance evidence.")
    code_review = _specialist("code-quality-reviewer", "Code Quality Reviewer", "Use for independent correctness and maintainability review.")
    risk_review = _specialist("engineering-risk-reviewer", "Engineering Risk Reviewer", "Use for security, supply chain, performance, concurrency and reliability review.")
    documentation = _specialist("documentation-and-release-readiness-specialist", "Documentation and Release Readiness Specialist", "Use for documentation and human release-readiness assessment.")

    lead = Agent(
        name="Software Development Lead",
        instructions=ROLE_INSTRUCTIONS["software-development-lead"],
        handoffs=[
            handoff(requirements), handoff(architect), handoff(implementation),
            handoff(testing), handoff(code_review), handoff(risk_review), handoff(documentation),
        ],
        input_guardrails=[sensitive_action_guardrail],
        output_guardrails=[unsupported_completion_claim_guardrail],
    )
    return {
        "software-development-lead": lead,
        "requirements-and-planning-specialist": requirements,
        "software-architect": architect,
        "implementation-and-maintenance-engineer": implementation,
        "test-and-quality-engineer": testing,
        "code-quality-reviewer": code_review,
        "engineering-risk-reviewer": risk_review,
        "documentation-and-release-readiness-specialist": documentation,
    }
